class Playground {
    async run(inputs) {
        const n = parseInt(inputs[0]);
        const board = Array.from({ length: n }, () => Array(n).fill(0));
        this.board.init(board);
        this.callstack.init();
        this.recursionTree.init();

        const solve = async (row, nodeId) => {
            this.callstack.pushFrame('solve', { row });
            this.recursionTree.enterNode(nodeId, `Row ${row}`);

            if (row === n) {
                this.log('Found a valid configuration!');
                this.callstack.popFrame(true);
                this.recursionTree.exitNode('#00f5a0');
                return true;
            }

            for (let col = 0; col < n; col++) {
                if (await this.isSafe(row, col, n)) {
                    this.board.setCell(row, col, 1);
                    this.board.highlight(row, col, '#00e0ff');
                    await this.await();

                    if (await solve(row + 1, `${nodeId}-${col}`)) {
                        this.callstack.popFrame(true);
                        this.recursionTree.exitNode('#00f5a0');
                        return true;
                    }

                    this.board.setCell(row, col, 0);
                    this.board.highlight(row, col, '#ffffff');
                    await this.await();
                }
            }

            this.callstack.popFrame(false);
            this.recursionTree.exitNode('#ff0000');
            return false;
        };

        return await solve(0, 'root');
    }

    async isSafe(row, col, n) {
        const grid = this.board.getValues();
        for (let i = 0; i < row; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] === 1) {
                    if (j === col || Math.abs(i - row) === Math.abs(j - col)) return false;
                }
            }
        }
        return true;
    }
}
